const html = `
<!DOCTYPE html>
<html lang="ru">

<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Atlas Underwriting</title>
<style>

body {
  font-family: Arial, sans-serif;
  background: #f4f7fb;
  margin: 0;
  padding: 40px;
}

.container {
  max-width: 700px;
  margin: auto;
}

.card {
  background: white;
  padding: 30px;
  border-radius: 16px;
  box-shadow: 0 4px 20px rgba(0,0,0,.08);
}

h1 {
  margin-top: 0;
  color: #163a70;
}

h2 {
  color: #163a70;
}

label {
  display: block;
  margin-bottom: 6px;
  margin-top: 15px;
  font-weight: bold;
}

input {
  width: 100%;
  padding: 12px;
  border: 1px solid #d9dce3;
  border-radius: 8px;
  box-sizing: border-box;
}

button {
  width: 100%;
  margin-top: 20px;
  padding: 14px;
  border: none;
  border-radius: 10px;
  background: #1f4fd7;
  color: white;
  font-size: 16px;
  cursor: pointer;
}

button:hover {
  opacity: 0.9;
}

button:disabled {
  opacity: .6;
}

.note {
  margin-top: 20px;
  color: #666;
  font-size: 14px;
}

.application-id {
  margin-bottom: 20px;
  padding: 10px;
  background: #eef4ff;
  border-radius: 8px;
  color: #163a70;
  font-weight: bold;
}

.status-box {
  margin-top: 20px;
  padding: 15px;
  background: #eef4ff;
  border-radius: 10px;
  font-weight: bold;
}

.small {
  margin-top: 10px;
  color: #666;
  font-size: 14px;
}

.success {
  color: #0f7b0f;
}

.auto-refresh-info {
  margin-top: 10px;
  padding: 8px 12px;
  background: #fff8e1;
  border-radius: 8px;
  color: #7a6000;
  font-size: 13px;
  font-weight: normal;
}

</style>
</head>

<body>

<div class="container">
<div class="card">

  <h1>Atlas Underwriting</h1>

  <div class="application-id">
    Номер заявки будет присвоен после отправки
  </div>

  <div id="formBlock">

    <p>Система автоматизированного кредитного анализа юридических лиц</p>

    <div id="creditForm">

      <label>ИНН*</label>
      <input id="inn" type="text">

      <label>КПП</label>
      <input id="kpp" type="text">

      <label>Сумма кредита (руб.)*</label>
      <input id="loan_amount" type="number">

      <label>Срок кредита (месяцев)*</label>
      <input id="loan_term" type="number">

      <button id="submitBtn" type="button" onclick="submitForm()">
        Отправить заявку
      </button>

    </div>

    <div class="note">
      После отправки заявки будет выполнен автоматический анализ компании и сформировано кредитное заключение.
    </div>

  </div>

  <div id="statusBlock" style="display:none">

    <h2 class="success">&#10003; Заявка принята в обработку</h2>

    <div class="application-id">
      ID заявки: <span id="appId">—</span>
    </div>

    <div class="status-box">
      Текущий этап:
      <div id="currentStatus">Заявка отправлена</div>
    </div>

    <div class="auto-refresh-info" id="autoRefreshInfo">
      &#128260; Статус обновляется автоматически каждые 10 секунд...
    </div>

    <button
      id="refreshBtn"
      type="button"
      onclick="refreshStatus()"
    >
      Обновить статус сейчас
    </button>

    <button
      id="reportBtn"
      type="button"
      style="display:none; background:#0f7b0f;"
      onclick="renderReport(window.finalReport)"
    >
      Открыть кредитное заключение
    </button>

    <div id="statusDate" class="small">Последнее обновление: —</div>

    <div id="reportContainer" style="display:none; margin-top:30px;"></div>

  </div>

</div>
</div>

<script>

var autoRefreshTimer = null;

function generateApplicationId() {
  return 'APP-' + Date.now() + '-' + Math.random().toString(36).substring(2, 10);
}

function getDisplayStatus(tool) {
  var map = {
    '01_Input_Form':                              'Проверка параметров заявки',
    '02_Input_Validation':                        'Формирование профиля компании',
    '03_Company_Profile_Builder':                 'Сбор данных компании',
    '03_DADATA_NOT_FOUND':                        'Компания не найдена в Dadata',
    '03_DADATA_API_ERROR':                        'Ошибка получения данных из Dadata',
    '04_Company_Profile_Data_Builder':            'Нормализация данных',
    '05_Company_Profile_Normalization_Builder':   'Финансовый анализ',
    '06_Financial_Agent_AI_Agent':                'Оценка финансового состояния',
    '07_Financial_Assessment':                    'Кредитная оценка',
    '07_Credit_Assessment':                       'Проверка регистрации',
    '06_Registration_Assessment':                 'Комплаенс проверка',
    '06_Compliance_Assessment':                   'Репутационный анализ',
    '06_FRAUD_ALLEGATION_FOUND':                  'Репутационный анализ',
    '06_REPUTATIONAL_SCANDAL_FOUND':              'Репутационный анализ',
    '06_NEGATIVE_MEDIA_COVERAGE':                 'Репутационный анализ',
    '06_PUBLIC_LITIGATION_MENTIONED':             'Репутационный анализ',
    '06_PUBLIC_ACCUSATION_FOUND':                 'Репутационный анализ',
    '06_POSITIVE_MEDIA_COVERAGE':                 'Репутационный анализ',
    '06_INDUSTRY_AWARD_FOUND':                    'Репутационный анализ',
    '06_PUBLIC_RECOGNITION_FOUND':                'Агрегация репутационных данных',
    '08_Reputation_Evidence_Aggregation':         'Оценка рисках',
    '08_Risk_Assessment':                         'Проверка кредитной политики',
    '09_Policy_Assessment':                       'Подготовка решения',
    '10_Decision_Explanation':                    'Кредитный комитет',
    '11_Credit_Committee_Chairman':               'Формирование кредитного заключения',
    '12_Final_Credit_Report':                     'Подготовка отчета',
    '13_Client_Report_Builder':                   'Отчет готов'
  };
  return map[tool] || tool || 'Статус неизвестен';
}

function startAutoRefresh() {
  stopAutoRefresh();
  autoRefreshTimer = setInterval(function() {
    refreshStatus();
  }, 10000);
}

function stopAutoRefresh() {
  if (autoRefreshTimer !== null) {
    clearInterval(autoRefreshTimer);
    autoRefreshTimer = null;
  }
}

async function submitForm() {
  var inn         = document.getElementById('inn').value;
  var kpp         = document.getElementById('kpp').value;
  var loan_amount = document.getElementById('loan_amount').value;
  var loan_term   = document.getElementById('loan_term').value;

  if (!inn || !loan_amount || !loan_term) {
    alert('Поля заполнены некорректно. Проверьте ИНН, КПП, сумму и срок кредита.');
    return;
  }

  var submitBtn = document.getElementById('submitBtn');
  submitBtn.disabled = true;
  submitBtn.innerText = 'Отправка заявки...';

  var applicationId = generateApplicationId();

  var formData = new FormData();
  formData.append('applicationId', applicationId);
  formData.append('inn',           inn);
  formData.append('kpp',           kpp);
  formData.append('loan_amount',   loan_amount);
  formData.append('loan_term',     loan_term);

  try {
    await fetch(
      'https://n8n-aigul-aigul1992.amvera.io/webhook/credit-application',
      { method: 'POST', body: formData }
    );

    document.getElementById('appId').innerText           = applicationId;
    document.getElementById('formBlock').style.display   = 'none';
    document.getElementById('statusBlock').style.display = 'block';

    startAutoRefresh();

  } catch (err) {
    alert('Ошибка отправки заявки');
    submitBtn.disabled  = false;
    submitBtn.innerText = 'Отправить заявку';
  }
}

async function refreshStatus() {
  var applicationId = document.getElementById('appId').innerText;
  var statusElement = document.getElementById('currentStatus');
  statusElement.innerText = 'Получение статуса...';

  try {
    var response = await fetch(
      'https://n8n-aigul-aigul1992.amvera.io/webhook/application-status',
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ applicationId: applicationId })
      }
    );

    var data = await response.json();

    if (!data.found) {
      statusElement.innerText = 'Заявка пока не найдена';
      return;
    }

    statusElement.innerText = getDisplayStatus(data.tool || data.status);

    var now = new Date().toLocaleTimeString('ru-RU');
    document.getElementById('statusDate').innerText =
      'Последнее обновление: ' + (data.date || now);

    if (data.completed) {

      stopAutoRefresh();

      document.getElementById('refreshBtn')
        .style.display = 'none';

      document.getElementById('autoRefreshInfo')
        .style.display = 'none';

      if (data.completionType === 'SUCCESS') {

        window.finalReport = data.report;

        document.getElementById('reportBtn')
          .style.display = 'block';

        document.getElementById('autoRefreshInfo')
          .innerText = '✓ Анализ завершён';

      }

      else if (
        data.completionType === 'DADATA_NOT_FOUND'
      ) {

        statusElement.innerText =
          'Компания не найдена в Dadata';

        document.getElementById('autoRefreshInfo')
          .innerText =
          '✖ Анализ завершён: компания не найдена';

      }

      else if (
        data.completionType === 'DADATA_API_ERROR'
      ) {

        statusElement.innerText =
          'Ошибка получения данных из Dadata';

        document.getElementById('autoRefreshInfo')
          .innerText =
          '✖ Анализ завершён: ошибка Dadata';

      }
      else if (
        data.completionType === 'VALIDATION_ERROR'
      ) {

        statusElement.innerText =
          (data.report && data.report.errorMessage)
            ? data.report.errorMessage
            : 'Ошибка проверки данных';

        document.getElementById('autoRefreshInfo')
          .innerText =
          '✖ Заявка отклонена на этапе проверки';

      }

    }

  } catch (err) {
    statusElement.innerText = 'Ошибка получения статуса';
  }
}

function renderReport(item) {
  var decisionMap = {
    APPROVE: 'ПРЕДВАРИТЕЛЬНО ОДОБРЕНО',
    REVIEW:  'ТРЕБУЕТСЯ ДОПОЛНИТЕЛЬНОЕ РАССМОТРЕНИЕ',
    DECLINE: 'ПРЕДВАРИТЕЛЬНЫЙ ОТКАЗ'
  };

  var riskMap = {
    LOW:    'Низкий',
    MEDIUM: 'Средний',
    HIGH:   'Высокий'
  };

  var strengths = (item.strengths_ru || [])
    .map(function(v) { return '<li>' + v + '</li>'; })
    .join('');

  var risks = (item.risks_ru || [])
    .map(function(v) { return '<li>' + v + '</li>'; })
    .join('');

  var evidences = (item.evidence_report || [])
    .map(function(section) {
      var cards = (section.evidences || [])
        .map(function(e) {
          return (
            '<div style="border-left:4px solid #d0d7e2;padding-left:15px;margin-bottom:15px;">' +
              '<b>' + (e.source || '') + '</b><br>' +
              '<small>' + (e.date || '') + '</small>' +
              '<p>' + (e.quote || '') + '</p>' +
              '<a href="' + (e.url || '#') + '" target="_blank">Открыть источник</a>' +
            '</div>'
          );
        })
        .join('');

      return (
        '<div style="margin-bottom:25px;">' +
          '<h3>' + (section.finding_title || '') + '</h3>' +
          '<p>Уверенность: ' + (section.confidence || '') + '</p>' +
          cards +
        '</div>'
      );
    })
    .join('');

  var container = document.getElementById('reportContainer');
  container.style.display = 'block';
  container.innerHTML = (
    '<div class="status-box">' +
      '<h2>Кредитное заключение</h2>' +
      '<p><b>Компания:</b> ' + (item.company_name || '') + '</p>' +
      '<p class="success">' + (decisionMap[item.decision] || item.decision || '') + '</p>' +
      '<p><b>Уровень риска:</b> ' + (riskMap[item.overall_risk] || item.overall_risk || '') + '</p>' +
      '<p><b>Риск-скор:</b> ' + (item.risk_score || '') + '</p>' +
    '</div>' +

    '<div class="status-box">' +
      '<h3>Положительные факторы</h3>' +
      '<ul>' + strengths + '</ul>' +
    '</div>' +

    '<div class="status-box">' +
      '<h3>Факторы внимания</h3>' +
      '<ul>' + risks + '</ul>' +
    '</div>' +

    '<div class="status-box">' +
      '<h3>Подтверждающие материалы</h3>' +
      evidences +
    '</div>'
  );
}

<\/script>

</body>
</html>
`;

return [{ json: { html } }];
